#include <bits/stdc++.h>
using namespace std;

const int N=8010,mod=1e9+7;

int n,a[N],pre[N],lst[N],f[N],h[N],c[N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        pre[i]=lst[a[i]];
        lst[a[i]]=i;
    }
    f[0]=1;
    for(int i=1;i<=n;i++){
        memset(c,0,sizeof(c));
        int cnt=1;
        if(pre[i])
            c[pre[i]-1]--;
        for(int j=i-1;j>=0;j--){
            cnt=(cnt+c[j])%mod;
            if(j && a[i]!=a[j]){
                c[j-1]=(c[j-1]+cnt)%mod;
                if(pre[j]) c[pre[j]-1]=(c[pre[j]-1]-cnt)%mod;
            }
            f[i]=(f[i]+1ll*f[j]*cnt)%mod;
        }
        // printf("%d ",f[i]);
    }
    memset(c,0,sizeof(c));
    int cnt=0;
    for(int i=n;i;i--){
        cnt=(cnt+c[i])%mod;
        h[i]=(cnt+1)%mod;
        c[i-1]=(c[i-1]+h[i])%mod;
        if(pre[i]) c[pre[i]-1]=(c[pre[i]-1]-h[i])%mod;
    }
    int ans=0;
    for(int i=1;i<=n;i++)
        ans=(ans+1ll*f[i]*h[i])%mod;
    printf("%d",(ans+mod)%mod);
    return 0;
}
